// Simple Test Map for FTEQW Engine
// File: test_assets/maps/test_simple.map
// 
// This is a basic Quake map file that creates a simple room with lighting
// Load it in the engine with: map test_simple

{
"classname" "worldspawn"
}
{
"classname" "light"
"origin" "0 0 100"
"light" "300"
}
{
"classname" "info_player_start"
"origin" "-200 -200 32"
"angle" "90"
}
{
"classname" "monster_knight"
"origin" "200 200 16"
"angle" "180"
}

// Brush 0: Floor
{
"texture" "FLOOR1_1"
"planes" (
(0 0 1, 0)
(-1 0 0, -256)
(0 -1 0, -256)
)
"mins" "-256 -256 0"
"maxs" "256 256 0"
}

